## ----radachart, fig.cap= "Radar plots of trained models and performance measures of two markers. Radar plots summarize the diagnostic performances of two markers and various combination methods in the training dataset. These plots illustrate the performance metrics such as AUC, ACC, SEN, SPE, PPV, and NPV measurements. In these plots, the width of the polygon formed by connecting each point indicates the model's performance in terms of AUC, ACC, SEN, SPE, PPV, and NPV metrics. It can be observed that the polygon associated with the Splines method occupies the most expensive area, which means that the Splines method performed better than the other methods.", fig.width=12, fig.height=8, fig.align='center', out.extra='keepaspectratio', out.width="90%"----
library(fmsb)
library(ggplot2)
library(scales)

# Demo data
data <- data.frame(
  row.names = c("d-dimer", "PCL", "add", "log(leukocyte)", "splines", "SVM"),
  AUC = c(0.8156966, 0.8794292, 0.8767035, 0.8022286, 0.9111752, 0.8754209),
  ACC = c(0.75, 0.80, 0.81, 0.77, 0.84, 0.82),
  SEN = c(0.86, 0.86, 0.88, 0.79, 0.86, 0.86),
  SPE = c(0.65, 0.75, 0.74, 0.74, 0.83, 0.78),
  PPV = c(0.70, 0.77, 0.76, 0.74, 0.82, 0.79),
  NPV = c(0.83, 0.85, 0.87, 0.79, 0.86, 0.85)
)

# Max-Min rows for scaling
max_min <- data.frame(
  AUC = c(1.0, 0.6), ACC = c(1.0, 0.6), SEN = c(1.0, 0.6),
  SPE = c(1.0, 0.6), PPV = c(1.0, 0.6), NPV = c(1.0, 0.6)
)
rownames(max_min) <- c("Max", "Min")

df <- rbind(max_min, data)

# Custom radar chart function
create_beautiful_radarchart <- function(data, color = "#00AFBB",
                                        vlabels = colnames(data), vlcex = 1.7,
                                        caxislabels = NULL, title = NULL, ...){
  radarchart(
    data, axistype = 1,
    cex.main = 2.5,
    # Customize the polygon
    pcol = color, pfcol = scales::alpha(color, 0.5), plwd = 2, plty = 1.5,
    # Customize the grid
    cglcol = "darkgrey", cglty = 1, cglwd = 0.8,
    # Customize the axis
    axislabcol = "darkgrey",
    calcex = 1.5,
    # Variable labels
    vlcex = vlcex, vlabels = vlabels,
    caxislabels = caxislabels, title = title, ...
  )
}

# Define colors and titles
colors <- c("#FA937E", "#89C665", "#C590B3", "#F07F28", "#5BADBF", "#88FFFF")
titles <- c("D-dimer", "Pepe, Cai & Langton",
            "Addition", "Log(leukocyte)", "Splines",
            "Support Vector Machine")

# Multiple radar charts in grid layout
par(mfrow = c(2,3), mar = c(0.8, 0.5, 3, .5))
for(i in 1:6){
  create_beautiful_radarchart(
    data = df[c(1, 2, i+2), ],
    caxislabels = c("0.6","0.7", "0.8", "0.9", "1.0"),
    color = colors[i], title = titles[i]
  )
}
par(mfrow = c(1,1))


## ----roc, fig.cap= "ROC curves. ROC curves for combined diagnostic tests, with sensitivity displayed on the y-axis and 1-specificity displayed on the x-axis. As can be observed, the combination score produced the highest AUC value, indicating that the combined strategy performs the best overall.", fig.align='center', out.extra='keepaspectratio', out.width="50%", fig.width=5, fig.height=5----
data(laparotomy)

# Splitting the data set into train and test (70%-30%)
set.seed(2128)
inTrain <- caret::createDataPartition(laparotomy$group, p = 0.7, list = FALSE)
trainData <- laparotomy[inTrain, ]
colnames(trainData) <- c("Group", "D_dimer", "log_leukocyte")
testData <- laparotomy[-inTrain, -1]

# define marker and status for combination function
markers <- trainData[, -1]
status <- factor(trainData$Group, levels = c("not_needed", "needed"))

# splines method (degree = 3 and degrees of freedom = 3)
fit.nonlin.splines <- nonlinComb(markers = markers, status = status, event = "needed",
                                 method = "splines", resample = "repeatedcv", nfolds = 5,
                                 nrepeats = 10, cutoff.method = "Youden", direction = "<",
                                 df1 = 3, df2 = 3, show.plot = TRUE)


## ----eval=TRUE, echo=TRUE-----------------------------------------------------
fit.nonlin.splines$AUC_table


## ----eval=TRUE, echo=TRUE-----------------------------------------------------
fit.nonlin.splines$MultComp_table


## ----eval=TRUE, echo=TRUE-----------------------------------------------------
fit.nonlin.splines$DiagStatCombined


## ----sensspec, eval=TRUE, echo=TRUE, fig.cap= "Kernel density, individual-value, and sens\\&spe plots of the combination score acquired with the training model. Kernel density of the combination score for two groups: needed and not needed. Individual-value graph with classes on the x-axis and combination score on the y-axis. Sensitivity and specificity graph of the combination score. While colors show each class in the density and individual-value plots, in the sensitivity and specificity plot, the colors represent the sensitivity and specificity of the combination score.", fig.align='center', out.extra='keepaspectratio', out.width="90%", fig.width=16, fig.height=6----
# draw distribution, dispersion, and specificity and sensitivity plots
p <- plotComb(fit.nonlin.splines, status)
p$all


## ----eval=TRUE, echo=TRUE-----------------------------------------------------
# To predict the test set
pred <- predict(fit.nonlin.splines, testData)
head(pred)


